# ── Patch HTML ────────────────────────────────────────────────────────────────
print("Patching HTML…")
html = HTML_SRC.read_text(encoding="utf-8")

# Replace each <canvas id="ID"> … </canvas> block with <img>
# Also nuke the entire <script> block that builds the JS charts
for cid, b64img in b64.items():
    # Replace canvas tag
    html = re.sub(
        rf'<canvas id="{cid}"></canvas>',
        f'<img src="data:image/png;base64,{b64img}" style="width:100%;display:block;" />',
        html
    )

# Remove the big JS chart script (everything between the chart comments)
html = re.sub(
    r'<!-- ══════════════ CHARTS ══════════════ -->.*</script>\s*</body>',
    '</body>',
    html, flags=re.DOTALL
)

# Remove CDN script tags (not needed without JS charts)
html = re.sub(r'<script src="https://cdn\.jsdelivr.*?></script>\n?', '', html)

# Remove results_chart canvas (figure 2 — keep only caption, drop canvas)
html = re.sub(
    r'<div class="chart-wrap"><canvas id="results_chart"></canvas></div>',
    '',
    html
)

HTML_TMP.write_text(html, encoding="utf-8")
print(f"Temp HTML → {HTML_TMP}")

# ── Chrome headless PDF ───────────────────────────────────────────────────────
chrome = shutil.which("google-chrome") or shutil.which("chromium")
if not chrome:
    sys.exit("Chrome not found")

print(f"Printing PDF via {chrome}…")
cmd = [
    chrome,
    "--headless=new", "--disable-gpu", "--no-sandbox",
    "--disable-dev-shm-usage",
    f"--print-to-pdf={PDF_OUT.resolve()}",
    "--print-to-pdf-no-header",
    "--no-pdf-header-footer",
    str(HTML_TMP),
]
result = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
if result.returncode != 0:
    print("STDERR:", result.stderr[:2000])
    sys.exit(f"Chrome failed (code {result.returncode})")

kb = PDF_OUT.stat().st_size // 1024
print(f"Done → {PDF_OUT}  ({kb} KB)")
